#include<bits/stdc++.h>
using namespace std;
int dp[5005],dp1[5005];
int num[5005];
int main()
{
	int n;
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>num[i];
		dp[i]=1;
	}
	for(int i=1;i<=n;i++){
		for(int j=1;j<i;j++){
			if(num[j]<num[i]){
				dp[i]=max(dp[i],dp[j]+1);
			}
		}
	}
    int maxi=0;
	for(int i=1;i<=n;i++){
		maxi=max(dp[i],maxi);
	}
	cout<<maxi;
}
